framework_css:
/*
  Core design system reflecting the early-2010s neon club aesthetic
*/

:root {
    /* Brand / primary */
    --color-primary-pink: #FF007F;
    --color-primary-black: #000000;

    /* Secondary / supporting */
    --color-secondary-pink: #E0006A;
    --color-content-bg: #F5FBB0;

    /* Accents & neutrals */
    --color-accent-dark: #333333;
    --color-accent-white: #FFFFFF;
    --color-neutral-light: #F7F7F7;
    --color-neutral-border: #DDDDDD;
    --color-neutral-mid: #999999;

    /* Semantic (not heavily surfaced in this framework, but available) */
    --color-success: #4CAF50;
    --color-error: #E53935;
    --color-warning: #FFC107;
    --color-info: #2196F3;

    /* Typography */
    --font-heading: "Space Grotesk", Helvetica, sans-serif;
    --font-body: "Work Sans", Arial, sans-serif;

    --font-size-h1: 32px;
    --font-size-h2: 24px;
    --font-size-h3: 18px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-xxs: 4px;
    --space-xs: 8px;
    --space-sm: 12px;
    --space-md: 16px;
    --space-lg: 24px;
    --space-xl: 32px;
    --space-xxl: 48px;

    /* Layout */
    --layout-width: 980px;
    --sidebar-width: 260px;
    --border-radius-soft: 4px;
    --border-radius-pill: 999px;
}

/* Global reset / base ----------------------------------------------------- */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-accent-dark);
    background-color: var(--color-primary-black);
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: var(--color-secondary-pink);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.page-background {
    background-color: var(--color-content-bg);
    min-height: 100vh;
}

.site-wrapper {
    width: var(--layout-width);
    margin: 0 auto;
}

/* Header ------------------------------------------------------------------ */

.site-header {
    background-color: var(--color-primary-black);
    padding-bottom: var(--space-xs);
}

.header-banner {
    background-color: var(--color-primary-black);
}

.header-banner-inner {
    width: var(--layout-width);
    margin: 0 auto;
    position: relative;
}

.header-logo {
    height: 120px;
    display: flex;
    align-items: center;
    justify-content: center;
    background-image:
        linear-gradient(90deg,
            var(--color-primary-black) 0%,
            var(--color-primary-black) 15%,
            var(--color-secondary-pink) 35%,
            var(--color-primary-black) 65%,
            var(--color-secondary-pink) 85%,
            var(--color-primary-black) 100%);
    border-bottom: 4px solid var(--color-secondary-pink);
}

.logo-text {
    font-family: var(--font-heading);
    font-size: 40px;
    font-weight: 700;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: var(--color-accent-white);
    text-shadow:
        0 0 4px rgba(0, 0, 0, 0.7),
        0 2px 0 rgba(0, 0, 0, 0.9),
        0 0 18px rgba(255, 0, 127, 0.8);
}

/* Primary navigation ------------------------------------------------------ */

.main-nav {
    margin-top: 0;
    background: linear-gradient(to bottom, #4a4a4a 0%, #222222 100%);
    border-radius: 12px 12px 0 0;
    padding: 0 var(--space-lg);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.15);
}

.main-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    flex-wrap: nowrap;
}

.nav-item {
    position: relative;
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

.nav-item a {
    display: block;
    padding: 10px 14px;
    color: var(--color-accent-white);
}

/* Vertical separators */

.nav-item + .nav-item::before {
    content: "|";
    color: var(--color-neutral-mid);
    margin-right: 8px;
    padding-left: 4px;
}

.nav-item--active > a {
    background-color: var(--color-primary-pink);
    color: var(--color-accent-white);
    border-radius: var(--border-radius-pill);
    box-shadow: 0 0 4px rgba(0, 0, 0, 0.6);
}

.nav-item a:hover,
.nav-item a:focus {
    background-color: var(--color-secondary-pink);
    border-radius: var(--border-radius-pill);
    text-decoration: none;
}

/* Layout: two-column fixed-width ----------------------------------------- */

.content-shell {
    display: flex;
    align-items: stretch;
    background-color: var(--color-content-bg);
    padding-bottom: var(--space-xl);
}

.sidebar {
    width: var(--sidebar-width);
    background-color: var(--color-primary-pink);
}

.sidebar-inner {
    padding: var(--space-lg) var(--space-sm);
}

.main-content {
    flex: 1;
    padding: var(--space-lg) var(--space-xl);
    min-height: 400px;
}

/* Sidebar media list ------------------------------------------------------ */

.sidebar-module {
    background-color: var(--color-secondary-pink);
    padding: var(--space-sm);
    border-radius: 0;
}

.sidebar-module--media {
    border: 2px solid var(--color-accent-white);
}

.sidebar-title {
    margin: 0 0 var(--space-md);
    padding: 0;
    font-family: var(--font-heading);
    font-size: var(--font-size-h3);
    font-weight: 600;
    text-align: center;
    color: var(--color-accent-white);
    text-transform: uppercase;
}

.sidebar-media-list {
    display: flex;
    flex-direction: column;
    gap: var(--space-md);
    margin-bottom: var(--space-md);
}

.media-card {
    background-color: var(--color-accent-white);
    padding: var(--space-xs);
    border: 3px solid var(--color-accent-black, #000000);
}

.media-card--placeholder {
    border-color: var(--color-neutral-border);
}

.media-thumb {
    background-color: var(--color-neutral-light);
    border: 4px solid var(--color-accent-white);
    box-shadow: 0 0 0 2px var(--color-accent-dark);
    height: 120px;
}

.media-caption {
    margin-top: var(--space-xs);
    font-size: var(--font-size-small);
    color: var(--color-primary-black);
    font-weight: 600;
    text-overflow: ellipsis;
    white-space: nowrap;
    overflow: hidden;
}

.sidebar-link {
    display: block;
    margin-top: var(--space-xs);
    text-align: center;
    font-size: var(--font-size-small);
    font-weight: 600;
    text-transform: uppercase;
    color: var(--color-accent-white);
}

.sidebar-link:hover,
.sidebar-link:focus {
    color: var(--color-accent-white);
    text-decoration: underline;
}

/* Footer ------------------------------------------------------------------ */

.site-footer {
    background: linear-gradient(to bottom, #232323 0%, #111111 100%);
    color: var(--color-neutral-mid);
    border-top: 4px solid var(--color-secondary-pink);
    padding: var(--space-md) 0 var(--space-lg);
}

.footer-inner {
    padding-top: var(--space-xs);
}

.footer-nav-list {
    list-style: none;
    margin: 0 0 var(--space-sm);
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
}

.footer-item {
    font-size: var(--font-size-small);
}

.footer-item a {
    color: var(--color-neutral-light);
    padding: 2px 4px;
}

.footer-item + .footer-item::before {
    content: "|";
    color: var(--color-neutral-mid);
    margin: 0 6px 0 2px;
}

.footer-item a:hover,
.footer-item a:focus {
    color: var(--color-accent-white);
    text-decoration: underline;
}

.footer-meta {
    margin: 0;
    text-align: center;
    font-size: var(--font-size-small);
}

.footer-meta-text {
    color: var(--color-neutral-mid);
}

/* Utility: typography inside main content -------------------------------- */

.main-content h1,
.main-content h2,
.main-content h3 {
    font-family: var(--font-heading);
    font-weight: 600;
    margin-top: 0;
}

.main-content h1 {
    font-size: var(--font-size-h1);
}

.main-content h2 {
    font-size: var(--font-size-h2);
}

.main-content h3 {
    font-size: var(--font-size-h3);
}

.main-content p {
    margin: 0 0 var(--space-md);
}

/* Responsive adaptations (keeps fixed aesthetic on large screens) -------- */

@media (max-width: 1024px) {
    .site-wrapper {
        width: 100%;
        max-width: var(--layout-width);
        padding: 0 var(--space-xs);
    }

    .header-banner-inner {
        width: 100%;
    }
}

@media (max-width: 800px) {
    .content-shell {
        flex-direction: column;
    }

    .sidebar {
        width: 100%;
    }

    .main-nav-list {
        flex-wrap: wrap;
        row-gap: 4px;
    }

    .nav-item + .nav-item::before {
        display: none;
    }
}
